                        : "cursor-not-allowed border border-zinc-200 bg-zinc-100 text-zinc-400",
                    ].join(" ")}
                  >
                    Adicionar ao carrinho
                  </button>
                </div>
              </div>
            </article>
          );
        })}
      </div>
    </div>
  );
}

