export default function BlogPagination({
  page,
  totalPages,
  onChange,
}: {
  page: number;
  totalPages: number;
  onChange: (n: number) => void;
}) {
  if (totalPages <= 1) return null;

  const pages = Array.from({ length: totalPages }, (_, i) => i + 1);

  return (
    <nav className="flex items-center justify-center gap-2 pt-2" aria-label="Paginao do blog">
      {pages.map((n) => {
        const active = n === page;
        return (
          <button
            key={n}
            type="button"
            onClick={() => onChange(n)}
            className={cn("inline-flex h-9 w-9 items-center justify-center rounded-full border text-sm font-semibold transition focus-visible :outline-none focus-visible:ring-2 focus-visible:ring-black/20",
              active
                 "border-zinc-900 bg-zinc-900 text-white"
                : "border-zinc-200 bg-white text-zinc-700 hover:bg-zinc-50",
            )}
            aria-current={active ? "page" : undefined}
          >
            {n}
          </button>
        );
      })}
    </nav>
  );
}

