                  <button
                    type= "button" ?                    className="inline-flex items-center gap-2 rounded-full border border-zinc-200 bg-white px-4 py-2 text-xs font-semibold text-zinc-700 transition hover :bg-zinc-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-black/20"
