export default function CartSaveShare() {
  const { items } = useCart();
  const [copied, setCopied] = useState(false);

  const shareUrl = useMemo(() => { const payload = encodeURIComponent(JSON.stringify(items.map((i) => ({ id : i.id, qty: i.qty }))));
    return `/cart?share=${payload}`;
  }, [items]);

  async function copy() {
    try {
      await navigator.clipboard.writeText(window.location.origin + shareUrl);
      setCopied(true);
      window.setTimeout(() => setCopied(false), 1200);
    } catch {
      setCopied(false);
    }
  }

  return (
    <div className="rounded-2xl border border-zinc-200 bg-white p-4">
      <p className="text-sm font-semibold text-zinc-900">Salvar e compartilhar</p>

      <div className="mt-3 grid gap-2">
