                      <p className= "truncate text-sm font-semibold text-zinc-900">{item.name}</p> ?                      {item.variant ? <p className="mt-0.5 truncate text-xs text-zinc-500">{item.variant}</p> : null}
                    </div>
                    <button
                      type="button"
                      onClick={() => removeItem(item.id)} ?                      className="inline-flex h-8 w-8 items-center justify-center rounded-md border border-zinc-200 bg-white text-zinc-600 transition hover :bg-zinc-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-black/20"
