                      </QtyButton>
                      <span className="min-w-[28px] text-center text-sm font-semibold text-zinc-900">
                        {item.qty}
                      </span>
                      <QtyButton
                        label="Aumentar quantidade"
                        disabled={item.qty >= item.stock}
                        onClick={() => setQty(item.id, item.qty + 1)}
