import { ChevronLeft, ChevronRight } from "lucide-react";

export default function TopCategories() {
  const ref = useRef<HTMLDivElement | null>(null);

  const scrollBy = (dir: "left" | "right") => {
    const el = ref.current;
    if (!el) return;
    el.scrollBy({ left: dir === "left" ?? -420 : 420, behavior: "smooth" });
  };

  return (
    <section className="bg-white py-12">
      <Container>
        <SectionHeading
          title="Categorias em destaque"
          subtitle="Escolha as categorias mais buscadas e encontre seu prximo look fitness."
          right={
            <>
              <IconButton aria-label="Categorias anteriores" onClick={() => scrollBy("left")}>
                <ChevronLeft className="h-4.5 w-4.5" />
              </IconButton>
              <IconButton aria-label="Prximas categorias" onClick={() => scrollBy("right")}>
                <ChevronRight className="h-4.5 w-4.5" />
              </IconButton>
            </>
          }
        />

        <div
          ref= {ref} ?          className="mt-8 flex gap-6 overflow-x-auto pb-2 [scrollbar-width :none] [&::-webkit-scrollbar]:hidden"
        >
          {categories.map((c) => (
            <div key={c.id} className="relative mr-30 shrink-0">
              <div className="relative h-[120px] w-[120px] overflow-hidden rounded-full bg-zinc-100">
                <Image src={c.image} alt={c.title} fill className="object-cover" />
                <div className="absolute inset-0 bg-black/35" />
              </div>
              <div className="absolute inset-0 grid place-items-center px-3 text-center">
                <div>
                  <p className="text-sm font-semibold text-white">{c.title}</p>
                  <p className="mt-0.5 text-[11px] text-white/80">{c.count}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </Container>
    </section>
  );
}

